import React, { useState } from 'react';

function SearchComponent({ entityName, entityIdKey, onSearch, onEdit, onDelete }) {
  const [searchId, setSearchId] = useState('');
  const [searchResult, setSearchResult] = useState(null);
  const [searchError, setSearchError] = useState(null);

  const gradientMap = {
    Bin: 'linear-gradient(135deg, #16a085, #2ecc71)',
    Authority: 'linear-gradient(135deg, #6a11cb, #2575fc)',
    Service: 'linear-gradient(135deg, #ff512f, #dd2476)',
    User: 'linear-gradient(135deg, #f7971e, #ffd200)',
    Driver: 'linear-gradient(135deg, #6dd5ed, #2193b0)',
    default: 'linear-gradient(135deg, #11998e, #38ef7d)',
  };
  const pageGradient = gradientMap[entityName] || gradientMap.default;

  const handleSearchClick = async () => {
    if (!searchId) {
      setSearchError(`Please enter a ${entityName} ID.`);
      setSearchResult(null);
      return;
    }
    setSearchError(null);
    try {
      const record = await onSearch(searchId);
      setSearchResult(record);
    } catch (err) {
      setSearchResult(null);
      setSearchError(err.message || 'Record not found.');
    }
  };

  return (
    <div
      style={{
        background: 'rgba(255,255,255,0.95)',
        padding: '40px',
        borderRadius: '24px',
        boxShadow: '0 12px 45px rgba(0,0,0,0.1)',
        margin: '30px 0',
        border: '1px solid rgba(0,0,0,0.1)',
      }}
    >
      <h3
        style={{
          fontSize: '1.7rem',
          fontWeight: '800',
          background: pageGradient,
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          textAlign: 'center',
          marginBottom: '25px',
        }}
      >
        🔍 Search {entityName} by ID
      </h3>

      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexWrap: 'wrap',
          gap: '10px',
        }}
      >
        <input
          type="number"
          value={searchId}
          onChange={(e) => setSearchId(e.target.value)}
          placeholder={`Enter ${entityName} ID`}
          style={{
            padding: '12px 18px',
            borderRadius: '12px',
            border: '2px solid rgba(0,0,0,0.1)',
            fontSize: '1rem',
            width: '220px',
          }}
        />
        <button
          onClick={handleSearchClick}
          style={{
            background: pageGradient,
            color: 'white',
            border: 'none',
            padding: '12px 28px',
            borderRadius: '12px',
            fontSize: '1rem',
            fontWeight: '600',
            cursor: 'pointer',
            boxShadow: '0 4px 15px rgba(0,0,0,0.2)',
          }}
        >
          Search
        </button>
      </div>

      {searchError && (
        <div
          style={{
            background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
            color: 'white',
            padding: '15px',
            borderRadius: '12px',
            marginTop: '20px',
            textAlign: 'center',
          }}
        >
          ⚠️ {searchError}
        </div>
      )}

      {searchResult && (
        <div style={{ marginTop: '30px', textAlign: 'center' }}>
          <h4
            style={{
              fontSize: '1.2rem',
              fontWeight: '600',
              color: '#333',
              marginBottom: '15px',
            }}
          >
            ✅ {entityName} Details (ID {searchResult[entityIdKey]})
          </h4>
          <div
            style={{
              display: 'inline-block',
              textAlign: 'left',
              background: 'rgba(255,255,255,0.9)',
              padding: '20px',
              borderRadius: '12px',
              boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
              border: '1px solid rgba(0,0,0,0.1)',
            }}
          >
            {Object.entries(searchResult).map(([key, value]) => {
              if (key === entityIdKey) return null;
              const displayKey = key.replace(/_/g, ' ').replace(/\b\w/g, (l) => l.toUpperCase());
              return (
                <p key={key}>
                  <strong>{displayKey}: </strong>
                  {value || 'N/A'}
                </p>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

export default SearchComponent;
